query:
-- Get the current Chaplaincy course ID
SELECT @chaplaincy_course_id := id FROM courses WHERE code = 'CHAP101' LIMIT 1;

-- Delete existing Chaplaincy lessons to avoid duplicates
DELETE FROM lessons WHERE courseId = @chaplaincy_course_id;

-- Verify deletion
SELECT COUNT(*) as remaining_lessons FROM lessons WHERE courseId = @chaplaincy_course_id;

